# fix_homepage_dark.ps1 - HomePage con dark mode
Write-Host "Aplicando dark mode a HomePage..." -ForegroundColor Cyan
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\modules\dashboard\pages\HomePage.tsx", $text, [System.Text.Encoding]::UTF8)
Write-Host "Listo!" -ForegroundColor Green
